/**
 * 针对完整角色卡的「某个方面」做局部微调，保留其余内容不变。
 * 例如：让性格更毒舌、把背景改成现代都市、丰富外貌描写等。
 */
export async function agentTweakCard(
  card: string,
  tweakRequest: string,
  settings: ToolsAiSettings,
  onChunk?: (fullText: string) => void,
): Promise<string> {
  const sys = `${SYSTEM_BASE}

当前任务：对现有角色卡做局部微调。
原则：
- 只按用户指出的方面调整，其余内容尽量原样保留，不要整卡重写。
- 输出调整后的【完整】YAML 角色卡（纯中文），只输出 YAML，不要解释、不要代码块标记。`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `现有角色卡：\n${card}\n\n要微调的方面：\n${tweakRequest}` },
  ];
  if (onChunk) {
    return (await streamToolsAiText(buildPayload(settings, messages), settings, onChunk)).trim();
  }
  return (await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings })).trim();
}

// ===== 会话草稿持久化 =====
// 按「角色 avatar」隔离保存，刷新/切角色后能接着上次的对话，避免生成到一半全丢。

function getAgentDraftKey(): string {
  let who = 'default';
  try {
    const TH = (window as any).TavernHelper;
    const char = TH?.getCharData?.('current');
    who = char?.avatar || char?.name || 'default';
  } catch {
    /* ignore */
  }
  return `maomaomz_card_agent_draft_${who}`;
}

/** 兜底用的全局最近一次草稿键 */
const AGENT_DRAFT_LAST_KEY = 'maomaomz_card_agent_draft_last';

/** 保存当前会话草稿（含模式） */
export function saveAgentDraft(state: AgentState, mode: string): void {
  try {
    const payload = JSON.stringify({ state, mode, savedAt: Date.now() });
    localStorage.setItem(getAgentDraftKey(), payload);
    // 同时写一份「最近一次」全局兜底，防止 avatar 变化/未就绪导致按角色键找不到
    localStorage.setItem(AGENT_DRAFT_LAST_KEY, payload);
  } catch (e) {
    console.warn('保存写卡会话草稿失败（忽略）:', e);
  }
}

/** 读取会话草稿；无则返回 null（先按角色找，找不到回落到最近一次的全局兜底） */
export function loadAgentDraft(): { state: AgentState; mode: string } | null {
  const tryParse = (raw: string | null) => {
    if (!raw) return null;
    try {
      const parsed = JSON.parse(raw);
      if (parsed?.state && Array.isArray(parsed.state.messages) && parsed.state.messages.length > 0) {
        return { state: parsed.state as AgentState, mode: parsed.mode || 'create' };
      }
    } catch {
      /* ignore */
    }
    return null;
  };

  try {
    // 1) 按当前角色读
    const byChar = tryParse(localStorage.getItem(getAgentDraftKey()));
    if (byChar) return byChar;
    // 2) 兜底：最近一次全局草稿
    return tryParse(localStorage.getItem(AGENT_DRAFT_LAST_KEY));
  } catch (e) {
    console.warn('读取写卡会话草稿失败（忽略）:', e);
    return null;
  }
}

/** 清除会话草稿 */
export function clearAgentDraft(): void {
  try {
    localStorage.removeItem(getAgentDraftKey());
  } catch {
    /* ignore */
  }
}

/** 读取当前酒馆角色卡的主要字段，拼成可读文本（供 agent 改写/续写用） */
export function readCurrentCharacterCard(): string {
  try {
    const TH = (window as any).TavernHelper;
    const char = TH?.getCharData?.('current');
    return charToText(char);
  } catch (e) {
    console.warn('读取当前角色卡失败:', e);
    return '';
  }
}

/** 把角色卡对象拼成可读文本 */
function charToText(char: any): string {
  if (!char) return '';
  const parts: string[] = [];
  if (char.name) parts.push(`名称：${char.name}`);
  const desc = char.description || char.data?.description;
  if (desc) parts.push(`描述：${desc}`);
  const persona = char.personality || char.data?.personality;
  if (persona) parts.push(`性格：${persona}`);
  const scenario = char.scenario || char.data?.scenario;
  if (scenario) parts.push(`场景：${scenario}`);
  const mes = char.first_mes || char.data?.first_mes;
  if (mes) parts.push(`开场白：${mes}`);
  const examples = char.mes_example || char.data?.mes_example;
  if (examples) parts.push(`对话示例：${examples}`);
  return parts.join('\n\n');
}

export interface CharacterListItem {
  avatar: string;
  name: string;
}

/** 列出酒馆里全部角色（用于「参考某张卡」的选择列表） */
export function listAllCharacters(): CharacterListItem[] {
  try {
    const st: any = typeof SillyTavern !== 'undefined' ? SillyTavern : (window as any).SillyTavern;
    const ctx = typeof st?.getContext === 'function' ? st.getContext() : st;
    const chars = ctx?.characters || st?.characters || [];
    return (chars as any[])
      .filter(c => c && c.avatar)
      .map(c => ({ avatar: String(c.avatar), name: String(c.name || c.avatar) }));
  } catch (e) {
    console.warn('获取角色列表失败:', e);
    return [];
  }
}

/** 按 avatar 读取指定角色卡的可读文本（用于参考） */
export function readCharacterCardByAvatar(avatar: string): string {
  try {
    const st: any = typeof SillyTavern !== 'undefined' ? SillyTavern : (window as any).SillyTavern;
    const ctx = typeof st?.getContext === 'function' ? st.getContext() : st;
    const chars = ctx?.characters || st?.characters || [];
    const char = (chars as any[]).find(c => c && c.avatar === avatar);
    return charToText(char);
  } catch (e) {
    console.warn('按 avatar 读取角色卡失败:', e);
    return '';
  }
}

/**
 * 改写/续写模式：基于「现有角色卡」+「用户的改写需求」产出新的完整角色卡（YAML）。
 * 与从零创作不同，这里要尽量保留原卡的设定基调，只按需求调整。
 */
export async function agentRewriteCard(
  existingCard: string,
  requirement: string,
  settings: ToolsAiSettings,
): Promise<string> {
  const sys = `${SYSTEM_BASE}

当前任务：在现有角色卡基础上按用户需求改写/扩写。
原则：
- 保留原卡的核心设定与基调，只按需求调整或补充，不要凭空推翻。
- 输出完整的 YAML 格式角色卡（纯中文），字段尽量齐全、有血有肉。
- 只输出 YAML，不要额外解释、不要 markdown 代码块标记。`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `现有角色卡：\n${existingCard}\n\n改写需求：\n${requirement}` },
  ];
  return (await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings })).trim();
}

export type CharField = 'description' | 'personality' | 'scenario' | 'first_mes' | 'mes_example';

/** 读取当前角色某个字段的现值（用于插入前备份） */
export function readCurrentCharacterField(field: CharField): string {
  try {
    const TH = (window as any).TavernHelper;
    const char = TH?.getCharData?.('current');
    if (char) {
      const v = char[field] ?? char.data?.[field];
      if (typeof v === 'string') return v;
    }
    const st: any = (window as any).SillyTavern || (window as any).parent?.SillyTavern;
    const ctx = typeof st?.getContext === 'function' ? st.getContext() : st;
    const charId = ctx?.characterId ?? st?.characterId;
    const c = ctx?.characters?.[charId] || st?.characters?.[charId];
    const v = c?.[field] ?? c?.data?.[field];
    return typeof v === 'string' ? v : '';
  } catch {
    return '';
  }
}

export interface InsertResult {
  ok: boolean;
  /** 该字段插入前的旧值，用于撤销 */
  backup: string;
  field: CharField;
}

/**
 * 把一张完整角色卡（YAML 或纯文本）插入到当前酒馆角色的指定字段。
 * 插入前会先读出旧值作为备份，返回的 backup 可传给 restoreCharacterField 撤销。
 */
export async function insertCardToCharacter(card: string, field: CharField = 'description'): Promise<InsertResult> {
  const backup = readCurrentCharacterField(field);
  const ok = await writeCharacterField(field, card);
  return { ok, backup, field };
}

/** 撤销：把某字段恢复成备份的旧值 */
export async function restoreCharacterField(field: CharField, backup: string): Promise<boolean> {
  return writeCharacterField(field, backup);
}

/** 实际写入角色字段（内部用） */
async function writeCharacterField(field: CharField, value: string): Promise<boolean> {
  const TH = (window as any).TavernHelper;
  const st = (window as any).SillyTavern || (window as any).parent?.SillyTavern;
  try {
    if (TH?.setCharData) {
      await TH.setCharData('current', { [field]: value });
      return true;
    }
    if (st?.getContext) {
      const ctx = st.getContext();
      const charId = ctx.characterId ?? ctx.characters?.findIndex?.((c: any) => c.avatar === ctx.character?.avatar);
      if (charId === undefined || charId < 0) throw new Error('未找到当前角色');
      const res = await fetch('/api/characters/edit', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...getSillyTavernRequestHeaders(),
        },
        body: JSON.stringify({ avatar_url: ctx.characters?.[charId]?.avatar, [field]: value }),
      });
      return res.ok;
    }
  } catch (e) {
    console.warn('写入角色字段失败:', e);
  }
  return false;
}
